+    #[test]
+    fn clock_advance_adds_duration() {
+        let mut clock = MockClock::new(0);
+        clock.advance(Duration::from_millis(500));
+        assert_eq!(clock.now_ms(), 500);
+        clock.advance(Duration::from_secs(2));
