+    #[test]
+    fn clock_advance_saturates_on_overflow() {
+        let mut clock = MockClock::new(u64::MAX - 10);
+        clock.advance(Duration::from_millis(100));
+        assert_eq!(clock.now_ms(), u64::MAX);
+    }
